const express = require('express')
const cors = require('cors')
const fs = require('fs')
const path = require('path')

const app = express()

app.use(cors())
app.use(express.json())

app.post('/write-map', (req, res) => {
  const { mapName, data } = req.body
  const mapsDir = path.join(process.cwd(), 'assets', 'maps')
  fs.mkdirSync(mapsDir, { recursive: true })
  const filePath = path.join(mapsDir, `${mapName}.json`)
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2))
  res.json({ ok: true, path: filePath })
})

app.post('/write-config', (req, res) => {
  const { data } = req.body
  const filePath = path.join(process.cwd(), 'maki.config.js')
  fs.writeFileSync(filePath, data)
  res.json({ ok: true })
})

app.get('/maki-config', (req, res) => {
  const configPath = path.join(process.cwd(), 'maki.config.js')
  try {
    const text = fs.readFileSync(configPath, 'utf8')
    const widthMatch  = text.match(/\bwidth\s*:\s*(\d+)/)
    const heightMatch = text.match(/\bheight\s*:\s*(\d+)/)
    const width  = widthMatch  ? parseInt(widthMatch[1])  : 800
    const height = heightMatch ? parseInt(heightMatch[1]) : 600
    res.json({ width, height })
  } catch {
    res.json({ width: 800, height: 600 })
  }
})

app.get('/list-assets', (req, res) => {
  const assetsDir = path.join(process.cwd(), 'assets')
  const excluded  = new Set(['maps', 'sprites'])
  const results   = []
  function scan(dir, rel) {
    let entries
    try { entries = fs.readdirSync(dir, { withFileTypes: true }) } catch { return }
    for (const entry of entries) {
      if (entry.isDirectory()) {
        if (!excluded.has(entry.name)) {
          scan(path.join(dir, entry.name), rel ? `${rel}/${entry.name}` : entry.name)
        }
      } else if (/\.(png|jpg|jpeg|gif|webp)$/i.test(entry.name)) {
        results.push(rel ? `${rel}/${entry.name}` : entry.name)
      }
    }
  }
  scan(assetsDir, '')
  res.json({ files: results })
})

app.get('/list-tilesets', (req, res) => {
  const assetsDir = path.join(process.cwd(), 'assets')
  const results = []
  function scan(dir, rel) {
    let entries
    try { entries = fs.readdirSync(dir, { withFileTypes: true }) } catch { return }
    for (const entry of entries) {
      if (entry.isDirectory()) {
        scan(path.join(dir, entry.name), rel ? `${rel}/${entry.name}` : entry.name)
      } else if (/\.(png|jpg|jpeg|gif|webp)$/i.test(entry.name)) {
        results.push(rel ? `assets/${rel}/${entry.name}` : `assets/${entry.name}`)
      }
    }
  }
  // Only scan rooms/ for tilesets — sprites, maps, and object folders excluded
  const roomsDir = path.join(assetsDir, 'rooms')
  scan(roomsDir, 'rooms')
  // Also include any other sibling directories that look like tilesets (not sprites/maps)
  let topLevel
  try { topLevel = fs.readdirSync(assetsDir, { withFileTypes: true }) } catch { topLevel = [] }
  for (const entry of topLevel) {
    if (entry.isDirectory() && !['rooms','sprites','maps'].includes(entry.name)) {
      scan(path.join(assetsDir, entry.name), entry.name)
    }
  }
  res.json({ files: results })
})

app.get('/tilemap-editor', (req, res) => {
  res.sendFile(path.join(__dirname, 'tilemap-editor.html'))
})

app.use('/assets', express.static(path.join(process.cwd(), 'assets')))

app.get('/maps/:mapName', (req, res) => {
  const filePath = path.join(process.cwd(), 'assets', 'maps', req.params.mapName)
  res.sendFile(filePath)
})

app.listen(3001, () => console.log('[maki] devserver ready on :3001'))

module.exports = app
